-- Premium AI modules: AI Quoting and AI Troubleshooting
CREATE TABLE IF NOT EXISTS ai_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), module_key text NOT NULL, related_type text, related_id uuid, status text DEFAULT 'queued', input jsonb DEFAULT '{}'::jsonb, output jsonb DEFAULT '{}'::jsonb, model text, search_used boolean DEFAULT false, confidence text, error_message text, created_by uuid REFERENCES users(id), created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_sources (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), ai_run_id uuid REFERENCES ai_runs(id) ON DELETE CASCADE, title text, url text, snippet text, source_type text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_quote_drafts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), request_id uuid REFERENCES work_requests(id), quote_id uuid REFERENCES quotes(id), ai_run_id uuid REFERENCES ai_runs(id), status text DEFAULT 'needs_review', confidence text, summary text, output jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_troubleshooting_reports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), job_id uuid REFERENCES jobs(id), work_request_id uuid REFERENCES work_requests(id), ai_run_id uuid REFERENCES ai_runs(id), status text DEFAULT 'draft', equipment_type text, make text, model text, error_code text, issue text, output jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_settings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text UNIQUE NOT NULL, value jsonb DEFAULT '{}'::jsonb, updated_at timestamptz DEFAULT now());
INSERT INTO ai_settings (key, value) VALUES ('ai_quoting', '{"enabled":true,"requireHumanApproval":true,"hourlyLaborRate":95,"minimumServiceFee":125,"markupPercentage":20,"taxPercentage":0,"preferredSuppliers":"","serviceArea":"","excludedJobTypes":"","confidenceThreshold":"medium","autoCreateQuoteDraft":true,"autoSendQuote":false,"openAiModel":"gpt-5.5","serpApiEnabled":false}'::jsonb) ON CONFLICT (key) DO NOTHING;
INSERT INTO permissions (key, module, description) VALUES ('ai_quoting.view','ai_quoting','View AI quoting'),('ai_quoting.manage','ai_quoting','Manage AI quoting'),('ai_troubleshooting.view','ai_troubleshooting','View AI troubleshooting'),('ai_troubleshooting.manage','ai_troubleshooting','Manage AI troubleshooting') ON CONFLICT (key) DO NOTHING;
